/**
 * Theme mode options
 */
type ThemeMode = 'light' | 'dark';
/**
 * Theme metadata information
 */
type ThemeMetadata = {
    name: string;
    version: string;
    mode: ThemeMode;
};
/**
 * Font weight definition following OpenType standard naming convention
 */
type FontWeight = {
    /** OpenType standard weight name (e.g., 'Thin', 'Regular', 'Bold', 'ExtraBold') */
    name: string;
    /** Numeric weight value (100, 200, 300, 400, 500, 600, 700, 800, 900, 950) */
    weight: number;
    /** Supported font file extensions (e.g., ['woff2', 'woff']) */
    extensions: string[];
    /** Function to get the font file URL */
    getUrl: (cdnUrl?: string, format?: string, fontVersion?: string) => string;
    /** Function to generate @font-face CSS  */
    getFontFaceStyle: (cdnUrl?: string, fontVersion?: string) => string;
};
/**
 * Font definition with name and available weights
 */
type Font = {
    /** Font family name (e.g., 'inter', 'proxima nova') */
    name: string;
    /** Array of available font weights */
    weights: FontWeight[];
};
/**
 * Options for configuring theme generation
 */
type GetGlobalThemeOptions = {
    /**
     * Theme name to retrieve (e.g., 'andes_x', 'andes_legacy')
     */
    name?: string;
    /**
     * Theme version to retrieve (semver string or 'latest')
     * @default 'latest'
     */
    version?: string;
    /**
     * Theme mode to use ('light' or 'dark')
     * @default 'light'
     */
    mode?: ThemeMode;
    /**
     * Disables global theme API calls and returns empty styles with fallback theme metadata
     * @default false
     */
    disableGlobalTheme?: boolean;
    /**
     * Strategy to use for theme resolution for native app.
     * @default 'overrideCookie'
     */
    strategy?: 'overrideCookie' | 'prioritizeCookie';
};
/**
 * Style object for inline styles support
 */
type StyleObject = {
    id: string;
    children: string;
};
/**
 * Internal theme response structure
 */
type ThemeResponse = {
    styles: StyleObject;
    fonts: Font[];
} & Partial<ThemeMetadata>;

/**
 * Retrieves the global theme based on the provided options and request context.
 *
 * Handles theme resolution with the following priority:
 * 1. Theme name and version from options (if name is provided in options)
 * 2. Theme info from cookie (if present)
 * 3. Default BU theme from API
 * 4. Fallback theme from frontend-config (if API fails)
 * 5. Fallback theme from fallback-themes directory (if config not available)
 *
 * The function also manages theme cookies for caching and sets request metadata
 * for observability purposes.
 *
 * @param options - Options for theme retrieval and formatting
 * @returns Theme response with styles object (id and children), name, version, mode, and fonts
 */
declare const getGlobalTheme: (options?: GetGlobalThemeOptions) => Promise<ThemeResponse>;

/**
 * Type guard for ThemeMode. Useful for narrowing values coming from
 * untrusted sources (cookies, query params, etc.).
 */
declare const isThemeMode: (value: unknown) => value is ThemeMode;

export { getGlobalTheme, isThemeMode };
export type { Font, GetGlobalThemeOptions, StyleObject, ThemeMetadata, ThemeMode, ThemeResponse };
